<script>

export default {
  props: {
    show: {
      type: Boolean,
      required: true,
    },
    qrData: {
      type: String,
      required: false,
    },
  },
  emits: ["close"],
  methods: {
    close() {
      this.$emit("close");
    },
    handleEscape(event) {
      if (event.key === "Escape") {
        this.close();
      }
    },
  },
  mounted() {
    window.addEventListener("keydown", this.handleEscape);
  },
  beforeUnmount() {
    window.removeEventListener("keydown", this.handleEscape);
  },
};
</script>

